// ─────────────────────────────────────────────
// STEP 1: Validate & prepare data
// ─────────────────────────────────────────────
const raw = $input.first().json;
const d = raw.body || raw; // n8n webhook v2 wraps POST body in .body

// Optional LINE ID whitelist (leave empty to allow all)
const WHITELIST = [];
if (WHITELIST.length > 0 && !WHITELIST.includes(d.lineUserId)) {
  throw new Error('Unauthorized LINE user: ' + d.lineUserId);
}

// Normalize weather
const wMap = {
  zh: { sunny: '晴 ☀️', rainy: '雨 🌧️', '': '-' },
  en: { sunny: 'Sunny ☀️', rainy: 'Rainy 🌧️', '': '-' },
  th: { sunny: 'แดดออก ☀️', rainy: 'ฝนตก 🌧️', '': '-' },
};

const mw = d.morningWeather || '';
const aw = d.afternoonWeather || '';

// Build photo URL block
const photoUrls = d.photoUrls || [];
const photoBlock = photoUrls.length > 0
  ? photoUrls.map((u, i) => `Photo ${i+1}: ${u}`).join('\n')
  : 'No photos';

// Build Gemini prompt
const formJson = JSON.stringify({
  language: d.language,
  lineDisplayName: d.lineDisplayName,
  supervisor: d.supervisor,
  projectName: d.projectName,
  constructionArea: d.constructionArea,
  contractor: d.contractor,
  date: d.date,
  morningWeather: d.morningWeather || 'not specified',
  afternoonWeather: d.afternoonWeather || 'not specified',
  constructionLocation: d.constructionLocation,
  constructionItems: d.constructionItems,
  workers: d.workers,
  materialsUsed: d.materialsUsed || 'None',
  equipment: d.equipment || 'None',
  communication: d.communication || 'None',
  otherNotes: d.otherNotes || 'None',
  samplingTests: d.samplingTests || 'None',
  qualityInspection: d.qualityInspection || 'None',
  photoCount: photoUrls.length,
  photoUrls: photoUrls,
}, null, 2);

const geminiPrompt = `You are a construction site reporting assistant.
Convert the form data below into two formatted daily work log reports.

Rules:
- Output ONLY a raw JSON object. No markdown, no code blocks, no explanation.
- The JSON must have exactly two keys: "zh_report" and "orig_report".
- zh_report: Full report in Traditional Chinese for the project manager.
- orig_report: Full report in the submission language ("en" = English, "th" = Thai) for the contractor.
- Use the emoji format below for both reports.
- Translate all field labels to the appropriate language.
- For empty/None fields, write "—" (em-dash).

Report format (both zh and orig must follow this structure):
📋 [Report title in language]
━━━━━━━━━━━━━━━━━━━━━━━━
📅 [Date label]: {date}
👤 [Filled by label]: {lineDisplayName}
🏗️ [Supervisor label]: {supervisor}
📋 [Project label]: {projectName}
🏭 [Area label]: {constructionArea}
🏢 [Contractor label]: {contractor}
━━━━━━━━━━━━━━━━━━━━━━━━
🌤️ [Morning weather label]: {morningWeather}
🌦️ [Afternoon weather label]: {afternoonWeather}
━━━━━━━━━━━━━━━━━━━━━━━━
📍 [Construction location label]:
{constructionLocation}
🔨 [Work items label]:
{constructionItems}
👷 [Workers label]: {workers} [persons label]
━━━━━━━━━━━━━━━━━━━━━━━━
📦 [Materials label]:
{materialsUsed}
🚧 [Equipment label]:
{equipment}
━━━━━━━━━━━━━━━━━━━━━━━━
💬 [Communication label]:
{communication}
📝 [Other notes label]:
{otherNotes}
🧪 [Sampling tests label]:
{samplingTests}
✅ [Quality inspection label]:
{qualityInspection}
━━━━━━━━━━━━━━━━━━━━━━━━
📷 [Photos label]: {photoCount} [photos label]
${photoUrls.length > 0 ? photoUrls.map((u,i)=>`Photo ${i+1}: ${u}`).join('\n') : ''}

Form data (JSON):
${formJson}`;

return [{
  json: {
    ...d,
    mwZh: wMap.zh[mw], awZh: wMap.zh[aw],
    photoUrls, photoBlock, photoCount: photoUrls.length,
    geminiPrompt,
  }
}];

// ─────────────────────────────────────────────
// STEP 3: Parse Gemini response + format messages
// ─────────────────────────────────────────────
const geminiRes = $input.first().json;

// Extract text from Gemini response
let rawText = '';
try {
  rawText = geminiRes.candidates[0].content.parts[0].text;
} catch(e) {
  throw new Error('Gemini response parse failed: ' + JSON.stringify(geminiRes));
}

// Parse the JSON from Gemini
let reports;
try {
  // Handle case where Gemini wraps in markdown code blocks
  const cleaned = rawText.replace(/^```json\n?|```$/g, '').trim();
  reports = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Gemini JSON parse failed: ' + rawText.substring(0, 200));
}

// Get original form data from previous node
// (We need to pass it through — use $('Prepare Data').first().json)
const d = $('Prepare Data').first().json;

const zhReport  = reports.zh_report  || '[Report generation failed]';
const origReport = reports.orig_report || '[Report generation failed]';

// Contractor message (original language)
const contractorMsg = origReport;

// Jerry's message (Chinese)
const jerryMsg = zhReport;

return [{
  json: {
    ...d,
    zhReport,
    origReport,
    contractorMsg,
    jerryMsg,
  }
}];

const contractorMsg = $('Parse & Format').first().json.contractorMsg;
const lineUserId = $('Webhook').first().json.body.lineUserId;

return [{
  json: {
    lineBody: JSON.stringify({
      to: lineUserId,
      messages: [{ type: "text", text: contractorMsg }]
    })
  }
}];
